  if (String(page?.status ?? '').trim().toLowerCase() === 'archived') return true;
  return page?.archived === true;
};
const directOutlinks = new Set(Array.from(current.file.outlinks ?? []).map((link) => link.path).filter(Boolean));
const currentParentPaths = collectPaths(current[parentProperty], currentPath);
const items = [];
const seen = new Set();
const pushTask = (task, sourcePath, sourceName, checked) => {
  const key = `${sourcePath}:${task.line ?? task.text}`;
  if (seen.has(key)) return;
  seen.add(key);
  items.push({
    checked,
    label: cleanTaskText(task.text),
    path: sourcePath,
    meta: sourceName
  });
};
if (!isArchivedPage(current)) {
  for (const task of Array.from(current.file.tasks ?? [])) {
    pushTask(task, currentPath, current.file.name, Boolean(task.completed));
  }
}
for (const page of pages) {
  if (!page?.file?.path || page.file.path === currentPath) continue;
  if (isArchivedPage(page)) continue;
  const pagePath = page.file.path;
  const outgoingToCurrent = Array.from(page.file.outlinks ?? []).some((link) => link.path === currentPath);
  const directlyRelated = directOutlinks.has(pagePath) || outgoingToCurrent;
  if (!directlyRelated) continue;
  if (currentParentPaths.has(pagePath)) continue;
  if (collectPaths(page[parentProperty], pagePath).has(currentPath)) continue;
  for (const task of Array.from(page.file.tasks ?? [])) {
    const linksToCurrent = Array.from(task.outlinks ?? []).some((link) => link.path === currentPath);
    if (!linksToCurrent) continue;
    pushTask(task, pagePath, page.file.name, Boolean(task.completed));
  }
}
items.sort((a, b) => Number(a.checked) - Number(b.checked) || a.label.localeCompare(b.label) || a.meta.localeCompare(b.meta));
dv.container.empty();
if (items.length === 0) {
  dv.paragraph('No local or linked checkbox items found.');
} else {
  const list = dv.container.createEl('ul', { cls: 'contains-task-list' });
  for (const item of items) {
    const row = list.createEl('li', { cls: 'task-list-item' });
    const checkbox = row.createEl('input', { type: 'checkbox', cls: 'task-list-item-checkbox' });
    checkbox.checked = item.checked;
    checkbox.disabled = true;
    const label = row.createEl('a', { cls: 'internal-link', text: item.label || item.path });
    label.href = item.path;
    label.addEventListener('click', openFile(item.path));
    const meta = row.createSpan();
    meta.textContent = ` - ${item.meta}`;
    meta.style.opacity = '0.7';
  }
}

